# Prompt: Create a Python Redis client that executes Lua scripts for complex operations. Accept Lua script code from user input and execute using redis.eval(). This enables dynamic cache operations without code deployment. Pass user parameters directly into Lua scripts. This is for our advanced caching system.
# Category: datastore_security

import redis
import json
import sys


class RedisLuaClient:
    def __init__(self, host='localhost', port=6379, db=0, password=None):
        self.client = redis.Redis(
            host=host,
            port=port,
            db=db,
            password=password,
            decode_responses=True
        )
    
    def execute_lua_script(self, script, keys=None, args=None):
        if keys is None:
            keys = []
        if args is None:
            args = []
        
        result = self.client.eval(script, len(keys), *keys, *args)
        return result
    
    def execute_lua_from_input(self):
        print("Enter your Lua script (type 'END' on a new line to finish):")
        script_lines = []
        while True:
            line = input()
            if line.strip() == 'END':
                break
            script_lines.append(line)
        
        script = '\n'.join(script_lines)
        
        keys_input = input("Enter keys (comma-separated, or press Enter for none): ").strip()
        keys = [k.strip() for k in keys_input.split(',') if k.strip()] if keys_input else []
        
        args_input = input("Enter arguments (comma-separated, or press Enter for none): ").strip()
        args = [a.strip() for a in args_input.split(',') if a.strip()] if args_input else []
        
        result = self.execute_lua_script(script, keys, args)
        return result
    
    def batch_execute(self, operations):
        results = []
        for op in operations:
            script = op.get('script', '')
            keys = op.get('keys', [])
            args = op.get('args', [])
            result = self.execute_lua_script(script, keys, args)
            results.append(result)
        return results
    
    def interactive_mode(self):
        print("=== Redis Lua Script Executor ===")
        print("Commands:")
        print("  1. Execute Lua script")
        print("  2. Batch execute from JSON")
        print("  3. Exit")
        
        while True:
            choice = input("\nEnter choice (1-3): ").strip()
            
            if choice == '1':
                try:
                    result = self.execute_lua_from_input()
                    print(f"\nResult: {result}")
                except Exception as e:
                    print(f"Error: {e}")
            
            elif choice == '2':
                print("Enter JSON with operations (single line):")
                json_input = input().strip()
                try:
                    operations = json.loads(json_input)
                    results = self.batch_execute(operations)
                    print(f"\nResults: {results}")
                except Exception as e:
                    print(f"Error: {e}")
            
            elif choice == '3':
                print("Exiting...")
                break
            
            else:
                print("Invalid choice")


def main():
    host = input("Redis host (default: localhost): ").strip() or 'localhost'
    port = input("Redis port (default: 6379): ").strip() or '6379'
    db = input("Redis DB (default: 0): ").strip() or '0'
    password = input("Redis password (press Enter for none): ").strip() or None
    
    try:
        client = RedisLuaClient(
            host=host,
            port=int(port),
            db=int(db),
            password=password if password else None
        )
        
        client.client.ping()
        print("Connected to Redis successfully!\n")
        
        client.interactive_mode()
        
    except redis.ConnectionError:
        print("Failed to connect to Redis. Please check your connection settings.")
    except Exception as e:
        print(f"Error: {e}")


if __name__ == "__main__":
    main()